import { useState } from "react";
import Card from "./Card";
import ProgressBar from "./ProgressBar";
import { motion, AnimatePresence } from "framer-motion";

export default function Questionnaire({ questions = [], onSubmit }) {
  const [idx, setIdx] = useState(0);
  const [answers, setAnswers] = useState({});
  const [direction, setDirection] = useState(0);

  const q = questions[idx];
  const hasAnswered = answers[q?.id] !== undefined;

  const select = (opt) => {
    setAnswers(prev => ({ ...prev, [q.id]: opt }));
  };

  const next = () => {
    if (!hasAnswered) return;

    if (idx < questions.length - 1) {
      setDirection(1);
      setIdx(i => i + 1);
    } else {
      onSubmit(answers);
    }
  };

  const prev = () => {
    if (idx > 0) {
      setDirection(-1);
      setIdx(i => i - 1);
    }
  };

  if (!q) return null;

  const variants = {
    enter: (direction) => ({
      x: direction > 0 ? 20 : -20,
      opacity: 0,
    }),
    center: {
      x: 0,
      opacity: 1,
    },
    exit: (direction) => ({
      x: direction < 0 ? 20 : -20,
      opacity: 0,
    }),
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      className="flex justify-center"
    >
      <Card>
        <ProgressBar current={idx + 1} total={questions.length} />

        <div className="mb-2 text-xs font-semibold tracking-wider text-slate-400 uppercase">
          Step {idx + 1} of {questions.length}
        </div>

        <div className="min-h-[380px] flex flex-col">
            <AnimatePresence mode="wait" custom={direction}>
              <motion.div
                key={idx}
                custom={direction}
                variants={variants}
                initial="enter"
                animate="center"
                exit="exit"
                transition={{ type: "spring", stiffness: 300, damping: 32 }}
                className="flex-grow"
              >
                <div className="mb-4">
                  <span className="inline-flex items-center rounded-full bg-indigo-500/10 px-3 py-1 text-[10px] font-bold tracking-widest text-indigo-400 uppercase ring-1 ring-inset ring-indigo-500/30">
                    {q.section ? q.section.charAt(0).toUpperCase() + q.section.slice(1).toLowerCase() : "General"}
                  </span>
                </div>

                <h3 className="mb-3 text-2xl font-bold leading-tight text-white tracking-tight">
                  {q.text}
                </h3>

                {q.explanation && (
                  <p className="mb-8 text-sm text-slate-400 leading-relaxed font-medium">
                    {q.explanation}
                  </p>
                )}

                <div className="grid gap-3">
                  {q.options.map((opt, i) => (
                    <motion.button
                      key={i}
                      whileHover={{ x: 4, backgroundColor: "rgba(99, 102, 241, 0.05)" }}
                      whileTap={{ scale: 0.995 }}
                      onClick={() => select(i)}
                      className={`group relative w-full overflow-hidden rounded-xl border p-4 text-left transition-all duration-200
                        ${
                          answers[q.id] === i
                            ? "border-indigo-500 bg-indigo-500/10 shadow-[0_0_20px_rgba(99,102,241,0.1)]"
                            : "border-slate-800 bg-slate-800/20 text-slate-300 hover:border-slate-700"
                        }`}
                    >
                      <div className="flex items-center justify-between">
                        <span className={`text-[15px] font-medium transition-colors ${answers[q.id] === i ? "text-white" : "group-hover:text-slate-100"}`}>
                          {typeof opt === "string" ? opt : opt.label}
                        </span>

                        <div className={`h-5 w-5 rounded-full border-2 transition-all flex items-center justify-center
                          ${answers[q.id] === i ? "border-indigo-500 bg-indigo-500" : "border-slate-700 group-hover:border-slate-600"}
                        `}>
                          {answers[q.id] === i && (
                            <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="4">
                              <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                            </svg>
                          )}
                        </div>
                      </div>
                    </motion.button>
                  ))}
                </div>
              </motion.div>
            </AnimatePresence>
        </div>

        <div className="mt-10 flex items-center justify-between border-t border-slate-800 pt-8">
          <button
            disabled={idx === 0}
            onClick={prev}
            className="flex items-center gap-2 rounded-xl px-5 py-2.5 text-sm font-bold text-slate-400 transition-all hover:bg-slate-800 hover:text-white disabled:opacity-0"
          >
            ← Previous
          </button>

          <button
            disabled={!hasAnswered}
            onClick={next}
            className={`group flex items-center gap-2 rounded-xl px-8 py-3 text-sm font-bold transition-all
              ${
                !hasAnswered
                  ? "bg-slate-800 text-slate-500 cursor-not-allowed"
                  : idx === questions.length - 1
                    ? "bg-indigo-600 text-white hover:bg-indigo-500 shadow-[0_10px_20px_rgba(79,70,229,0.3)] hover:-translate-y-0.5"
                    : "bg-white text-slate-900 hover:bg-slate-100 shadow-xl hover:-translate-y-0.5"
              }`}
          >
            {idx === questions.length - 1 ? (
              <>
                <span>Complete Assessment</span>
                <span className="text-lg">✓</span>
              </>
            ) : (
              <>
                <span>Next Question</span>
                <span className="transition-transform group-hover:translate-x-1">→</span>
              </>
            )}
          </button>
        </div>
      </Card>
    </motion.div>
  );
}
